/// Extracts the first grapheme cluster of the string.
/// Fails with an error if the string is empty.
#[func]
pub fn first(
    &self,
    /// If given, the first grapheme cluster whose leading character
    /// belongs to this class is returned instead of the very first one.
    #[named]
    pattern: Option<CharPattern>,
    /// If given, transforms the case of the returned grapheme cluster.
    #[named]
    case: Option<Case>,
) -> StrResult<Str> {
    let grapheme = match pattern {
        None => self.0.graphemes(true).next().ok_or_else(string_is_empty)?,
        Some(pattern) => self
            .0
            .graphemes(true)
            .find(|g| pattern.matches(g))
            .ok_or_else(|| no_match_for_pattern(pattern))?,
    };
    Ok(apply_case(grapheme, case))
}

