/// A case to transform a grapheme cluster into.
#[derive(Debug, Copy, Clone, Eq, PartialEq)]
pub enum Case {
    /// Everything uppercase.
    Upper,
    /// Everything lowercase.
    Lower,
    /// The first letter uppercase, the rest lowercase.
    Title,
}

cast! {
    Case,
    self => match self {
        Self::Upper => "upper".into_value(),
        Self::Lower => "lower".into_value(),
        Self::Title => "title".into_value(),
    },
    "upper" => Self::Upper,
    "lower" => Self::Lower,
    "title" => Self::Title,
}

/// Transforms a grapheme cluster into the requested case, if any.
fn apply_case(grapheme: &str, case: Option<Case>) -> Str {
    match case {
        None => grapheme.into(),
        Some(Case::Upper) => grapheme.to_uppercase().into(),
        Some(Case::Lower) => grapheme.to_lowercase().into(),
        Some(Case::Title) => {
            let mut chars = grapheme.chars();
            match chars.next() {
                Some(first) => {
                    let mut out: EcoString =
                        first.to_uppercase().collect::<String>().into();
                    out.push_str(&chars.as_str().to_lowercase());
                    out.into()
                }
                None => grapheme.into(),
            }
        }
    }
}

